css:
.vbes-pricing {
  max-width: 360px;
  margin: 0 auto;
  background: #fff;
  border: 2px solid #e9ecef;
  border-radius: 12px;
  padding: 40px 32px;
  text-align: center;
}
.vbes-pricing__plan {
  font-size: 1.125rem;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  color: {{accent_color}};
  margin: 0 0 16px;
}
.vbes-pricing__amount {
  font-size: 3rem;
  font-weight: 800;
  color: #1a1a1a;
}
.vbes-pricing__period {
  font-size: 1rem;
  color: #777;
}
.vbes-pricing__features {
  text-align: left;
  padding: 24px 0;
  margin: 24px 0;
  border-top: 1px solid #e9ecef;
  border-bottom: 1px solid #e9ecef;
  font-size: 0.95rem;
  line-height: 2;
  color: #444;
}
.vbes-pricing__btn {
  display: inline-block;
  width: 100%;
  padding: 14px;
  background: {{accent_color}};
  color: #fff;
  text-decoration: none;
  border-radius: 6px;
  font-weight: 600;
  font-size: 1rem;
  transition: opacity 0.2s;
  box-sizing: border-box;
}
.vbes-pricing__btn:hover {
  opacity: 0.9;
}
